INSERT INTO `jobs` (`id`, `job_title`, `description`, `requirements`, `location`, `job_type`, `salary_min`, `salary_max`, `currency`, `is_remote`, `status`, `company_id`, `created_by`, `created_at`, `updated_at`, `expires_at`, `skills`, `education_qualification`, `work_location_preference`, `experience_min`, `experience_max`, `department`, `role`, `employment_type`, `location_city`, `location_state`, `location_country`, `industry`, `diversity_hiring`, `responsibilities`, `no_of_openings`, `notice_period_days`, `contact_person_name`, `contact_person_email`) VALUES
('113c3b0b-bc9f-4fe6-9c0b-1f75592e97c5', 'Telecaller', 'Telecaller for insurance and MF clients\nOutcall to customers and explain about insurance, MF products', '10+2 minimum Education\nMinimum 6 months experience in any outbound Call centre', 'Hyderabad, Telangana', 'full-time', 100000.00, 300000.00, 'INR', 0, 'active', 'c49c5aed-9b26-4410-accc-3f8701d41402', '9e6947ff-1631-483b-88c7-ed4d16ad12b4', '2026-04-01 15:28:12', '2026-04-01 15:28:12', NULL, NULL, 'any', 'wfo', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL),
('182e0739-bb42-4c9f-9870-c35ac315b399', 'Full Stack Developer', 'Your potential, unleashed.\n\nIndias impact on the global economy has increased at an exponential rate and Deloitte presents an opportunity to unleash and realise your potential amongst cutting edge leaders, and organizations shaping the future of the region, and indeed, the world beyond.\n\n\nAt Deloitte, your whole self to work, every day. Combine that with our drive to propel with purpose and you have the perfect playground to collaborate, innovate, grow, and make an impact that matters.\n\n\nThe team\n\nThe Digital Excellence Centre is responsible for building products and platforms for Deloitte India that focuses on providing extraordinary customer experience by putting design thinking with trailblazing technology in the center of what they do. The diverse team consists of subject matter experts, technology specialists, quality engineers, user experience researchers & designers, data scientists and product managers.\n\nInspiring - Leading with integrity to build inclusion and motivation\nCommitted to creating purpose - Creating a sense of vision and purpose\nAgile - Achieving high-quality results through collaboration and Team unity\nSkilled at building diverse capability - Developing diverse capabilities for the future\nPersuasive / Influencing - Persuading and influencing stakeholders\nCollaborating - Partnering to build new solutions\nDelivering value - Showing commercial acumen\nCommitted to expanding business - Leveraging new business opportunities\nAnalytical Acumen - Leveraging data to recommend impactful approach and solutions through the power of analysis and visualization\nEffective communication Must be well abled to have well-structured and well-articulated conversations to achieve win-win possibilities\nEngagement Management / Delivery Excellence - Effectively managing engagement(s) to ensure timely and proactive execution as well as course correction for\nthe success of engagement(s)\n\nManaging change - Responding to changing environment with resilience\nManaging Quality & Risk - Delivering high quality results and mitigating risks with utmost integrity and precision\nStrategic Thinking & Problem Solving - Applying strategic mindset to solve business issues and complex problems\nTech Savvy - Leveraging ethical technology practices to deliver high impact for clients and for Deloitte\nEmpathetic leadership and inclusivity - creating a safe and thriving environment where everyone\'s valued for who they are, use empathy to understand others to adapt our behaviours and attitudes to become more inclusive.', 'As a prospective candidate, you should possess:\n\nExperience: 2 to 5 years\n2+ years of relevant experience in software development and building web applications.\nExperience in leading a team of developers\nSound knowledge on Data Structures, Algorithms and excellent problem solving skills.\nShould have experience in Python, JavaScript/Typescript and SQL.\nDemonstrated technical capability in developing applications using any industry-standard RDBMS/NoSQL Databases.\nExperience in JavaScript dialects like ES6 TypeScript.\nExperience in writing reusable, testable, and efficient code\nDesign and implementation of low-latency, high-availability, and performant applications\nImplementation of security and data protection best practices.\nHands on experience on React.js, Node.js, FastAPI frameworks.\nExperience in building applications on cloud platforms like AWS/Azure/GCP.\nExperience in writing unit test cases using Jest, Mocha and PyTest frameworks\nComfortable working in Agile methodology, eager to learn and grow.', 'Bangalore, Karnataka', 'full-time', 500000.00, 800000.00, 'INR', 0, 'active', '3d00d233-6931-42a0-b595-26a83fe6aace', '5c6479bc-157e-4de3-af63-37347cd521d8', '2026-03-22 13:27:26', '2026-03-22 13:27:26', NULL, NULL, 'bachelors', 'hybrid', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL),
('23b80807-37b8-492a-a141-4096514f5657', 'Application Developer', 'Application Developer with experience in Python, FastAPI etc\nExperience in front-end is advantage', 'Graduate with 1year relevant experience', 'Hyderabad, Telangana', 'full-time', 500000.00, 800000.00, 'INR', 0, 'active', '3dd70181-2905-4f41-b074-084c05386b4a', 'fd46f8e0-cb83-43d2-a840-d5e26cc72ff9', '2026-03-21 08:54:55', '2026-03-21 08:54:55', NULL, NULL, 'bachelors', 'wfo', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL),
