('a6e3100d-2cdf-11f1-9793-f08cebf81990', '900a8a68-04af-4521-9236-97d5b1735e1a', 'https://storage.skreenit.com/datastorage/videos/20260331_142636_e8ae0c6a.webm', '2026-03-31 08:57:31', '{\"candidate_id\": \"900a8a68-04af-4521-9236-97d5b1735e1a\", \"video_url\": \"https://storage.skreenit.com/datastorage/videos/20260331_142636_e8ae0c6a.webm\", \"analyzed_at\": \"2026-03-31T08:58:07.026017+00:00\", \"transcription\": {\"transcript\": \"My name is Rilata Banot. I have completed my graduation in 2020. After my graduation I started my career as call center executive. I work with a company called HRH. HRH service is private-tripped in Hyderabad. I have one year experience as customer service executive. After one year I changed my domain into HR. Currently I am working as an HR executive with dipping liquid.\", \"word_count\": 65, \"duration_seconds\": 0, \"wpm\": 0, \"filler_words\": 0, \"language\": \"en\"}, \"visual_analysis\": {\"emotion_distribution\": {\"neutral\": 100.0}, \"dominant_emotion\": \"neutral\", \"face_presence_rate\": 100.0, \"avg_confidence\": 63.9, \"total_frames_analyzed\": 1, \"face_detected_frames\": 1, \"duration_seconds\": 32.1}, \"summary\": {\"speaking_pace\": 121, \"word_count\": 65, \"duration\": 32.1, \"filler_words\": 0, \"confidence_score\": 63.9, \"dominant_emotion\": \"neutral\", \"face_presence\": 100.0, \"overall_score\": 90}}', '2026-03-31 08:58:07', 'intro', '58b66020c0b56e5e15bd1dbae8fbdfef01d616300170ae5686af56f1ef382396', NULL, NULL),
('a7b57fe3-2ff6-11f1-9793-f08cebf81990', 'b855cb5c-24a6-41db-b7f2-0f098b6a7f60', 'https://storage.skreenit.com/datastorage/videos/20260404_124837_87b9eddc.webm', '2026-04-04 07:19:44', '{\"candidate_id\": \"b855cb5c-24a6-41db-b7f2-0f098b6a7f60\", \"video_url\": \"https://storage.skreenit.com/datastorage/videos/20260404_124837_87b9eddc.webm\", \"analyzed_at\": \"2026-04-04T11:29:27.266837+00:00\", \"transcription\": {\"transcript\": \"My name is Pravin Kumar. I am based out of Chennai. I am basically from Maloooth. I can speak three languages, Telugu, Hindi, English. Additionally I can speak Tamil. I have ten years of experience in HR. I started my career with a consultancy as a recruiter. After working for one and a half years, I got an opportunity to go with Spursch video services. Since then, I was working in I joined Spursch as an executive. After a couple of years, I got promoted and till manager level, I worked with the same company for five years. Meanwhile, company name got changed. Initially, it was Spursch, then it moved to Etherinet, then Sarco, again back to Etherinet. After Etherinet, I joined SquareBibyo Services as a manager, which I have worked with for four years. I am working with SquareBibyo Services. Here, I manage all HR activities for either one location. It includes my recruitment as well as entire\", \"word_count\": 159, \"duration_seconds\": 0, \"wpm\": 0, \"filler_words\": 1, \"language\": \"en\"}, \"visual_analysis\": {\"emotion_distribution\": {}, \"dominant_emotion\": \"unknown\", \"face_presence_rate\": 0.0, \"avg_confidence\": 0, \"total_frames_analyzed\": 1, \"face_detected_frames\": 0, \"duration_seconds\": 87.3}, \"nlp_analysis\": {\"grammar\": {\"score\": 100, \"error_count\": 13, \"errors_per_100_words\": 8.18, \"issues\": [], \"error_breakdown\": {\"spelling\": 0, \"grammar\": 0, \"punctuation\": 0, \"style\": 1}, \"error\": \"\'Match\' object has no attribute \'length\'\"}, \"sentence_formation\": {\"score\": 65, \"total_sentence