--
-- Table structure for table `interview_responses`
--

CREATE TABLE `interview_responses` (
  `id` varchar(36) NOT NULL,
  `application_id` varchar(36) NOT NULL,
  `candidate_id` varchar(36) NOT NULL,
  `question` text DEFAULT NULL,
  `video_url` varchar(500) NOT NULL,
  `video_path` varchar(500) DEFAULT NULL,
  `question_index` int(11) DEFAULT 0,
  `status` enum('pending_review','reviewed','approved','rejected') NOT NULL,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `responded_at` datetime DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Triggers `interview_responses`
--
DELIMITER $$
CREATE TRIGGER `update_application_status_after_responses` AFTER INSERT ON `interview_responses` FOR EACH ROW BEGIN
    DECLARE total_questions INT;
    DECLARE submitted_responses INT;
    
    -- Get total questions for this application
    SELECT COUNT(*) INTO total_questions
    FROM job_applications 
    WHERE id = NEW.application_id 
    AND interview_questions IS NOT NULL;
    
    -- Get submitted responses for this application
    SELECT COUNT(DISTINCT question_index) INTO submitted_responses
    FROM interview_responses 
    WHERE application_id = NEW.application_id;
    
    -- Update status if all responses submitted
    IF total_questions > 0 AND submitted_responses >= total_questions THEN
        UPDATE job_applications 
        SET status = 'responses_submitted', updated_at = NOW()
        WHERE id = NEW.application_id;
    END IF;
END
$$
DELIMITER ;

